module RefModule (
    input clk,
    input rst,
    input load,
    input [7:0] d,
    output [7:0] q
);

    reg [7:0] obf_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            obf_q_reg <= 8'b00000000;
        else if (load)
            obf_q_reg <= d;
    end

    assign q = obf_q_reg;

endmodule
